// === src/pages/Home.js ===
import React from 'react';
import { Link } from 'react-router-dom';
import './Home.css';

const categories = [
  { name: 'Plants', image: 'https://cdn.shopify.com/s/files/1/0059/8835/2052/files/Air-Purifying-Plants.jpg' },
  { name: 'Seeds', image: 'https://cdn.shopify.com/s/files/1/0059/8835/2052/files/seeds_homepage.jpg' },
  { name: 'Pots', image: 'https://cdn.shopify.com/s/files/1/0059/8835/2052/files/ceramic_pots_homepage.jpg' },
  { name: 'Flowers', image: 'https://cdn.shopify.com/s/files/1/0059/8835/2052/files/flowering_plants_homepage.jpg' },
  { name: 'Decor', image: 'https://cdn.shopify.com/s/files/1/0059/8835/2052/files/plant_decor_homepage.jpg' },
];

const Home = () => {
  return (
    <div className="home-container">
      <section className="hero-banner">
        <img
          src="https://cdn.shopify.com/s/files/1/0059/8835/2052/files/banner_home.jpg"
          alt="Ugaoo style banner"
        />
      </section>

      <section className="category-section">
        <h2>Explore by Category</h2>
        <div className="category-grid">
          {categories.map((cat, idx) => (
            <Link to={`/shop?category=${cat.name}`} className="category-card" key={idx}>
              <img src={cat.image} alt={cat.name} />
              <p>{cat.name}</p>
            </Link>
          ))}
        </div>
      </section>
    </div>
  );
};

export default Home;
